import {
  Directive,
  ElementRef,
  HostListener,
  OnInit,
  Renderer2,
  inject,
  input,
} from '@angular/core';

@Directive({
  selector: 'img[appImgFallback]',
  standalone: true,
})
export class ImgFallbackDirective implements OnInit {
  readonly fallbackText = input<string>('?');

  private readonly imgRef = inject<ElementRef<HTMLImageElement>>(ElementRef);
  private readonly renderer = inject(Renderer2);

  ngOnInit(): void {
    const img = this.imgRef.nativeElement;
    // Handle already-failed images (e.g. cached 404s) so the fallback shows
    // immediately rather than waiting for a second network error event.
    if (img.complete && img.naturalWidth === 0) {
      this.showFallback();
    }
  }

  @HostListener('error')
  onError(): void {
    this.showFallback();
  }

  private showFallback(): void {
    const img = this.imgRef.nativeElement;
    if (!img.parentElement) return;

    const fallback = this.renderer.createElement('div') as HTMLElement;

    // NOTE: Class filtering assumes Tailwind CSS utility prefixes (w-, h-, rounded, shadow).
    const imgClasses = Array.from(img.classList);
    const sizeClasses = imgClasses.filter(
      (cls) =>
        cls.startsWith('w-') ||
        cls.startsWith('h-') ||
        cls.startsWith('rounded') ||
        cls.startsWith('shadow'),
    );

    const classes = [
      ...sizeClasses,
      'flex',
      'items-center',
      'justify-center',
      'bg-primary',
      'text-primary-contrast',
      this.textSizeFromImgClasses(imgClasses),
      'font-medium',
      'select-none',
      'shrink-0',
    ];

    classes.forEach((cls) => this.renderer.addClass(fallback, cls));

    const text = this.renderer.createText(
      (this.fallbackText() ?? '?').charAt(0).toUpperCase(),
    );
    this.renderer.appendChild(fallback, text);

    // Replace the img entirely rather than hiding it, to avoid accumulating
    // hidden elements in the DOM when many images fail.
    img.parentElement.replaceChild(fallback, img);
  }

  /** Pick a text size proportional to the w-* value on the image. */
  private textSizeFromImgClasses(classes: string[]): string {
    const widthClass = classes.find((cls) => /^w-\d+$/.test(cls)) ?? '';
    const size = widthClass ? Number.parseInt(widthClass.slice(2), 10) : 0;

    if (size >= 28) return 'text-4xl';
    if (size >= 16) return 'text-3xl';
    if (size >= 10) return 'text-2xl';
    return 'text-sm';
  }
}
